import { Auth } from '@/store/_auth';
import {
  FolderOpenOutlined,
  FolderOpenTwoTone,
  GlobalOutlined,
  UserOutlined,
} from '@ant-design/icons';
import { Divider, Flex, Space, Tabs, Typography } from 'antd';
import { useEffect, useMemo, useState } from 'react';
import { useSelector } from 'react-redux';
import { useNavigate, useSearchParams } from 'react-router-dom';
import { CreateLibraryButton } from './CreateLibraryButton';
import { LibraryList } from './LibraryList';

export const LibraryListPage: React.FC = () => {
  const navigate = useNavigate();
  const [searchParams, setSearchParams] = useSearchParams();
  const isAdmin = useSelector(Auth.select.isAdmin);
  const isLocalUser = useSelector(Auth.select.isLocal);

  const [refresh, setRefresh] = useState(0);

  const tab = useMemo(() => {
    return searchParams.get('tab') || (isAdmin ? 'all' : 'my');
  }, [searchParams, isAdmin]);

  useEffect(() => {
    navigate('/libraries');
  }, [isAdmin, navigate]);

  return (
    <>
      <Flex wrap align="baseline" justify="space-between">
        <Typography.Title level={2}>
          <FolderOpenTwoTone /> Libraries
        </Typography.Title>
        <CreateLibraryButton onSuccess={() => setRefresh((v) => v + 1)} />
      </Flex>

      <Divider size="small" />

      <Tabs
        activeKey={tab}
        onChange={(key) => setSearchParams({ tab: key })}
        size="large"
        tabBarGutter={24}
        tabBarStyle={{
          display: isLocalUser ? 'none' : undefined,
        }}
        items={[
          {
            key: 'my',
            label: (
              <Typography.Text style={{ color: '#3cf' }}>
                <Space>
                  <UserOutlined /> My Libraries
                </Space>
              </Typography.Text>
            ),
            children: <LibraryList type={'my'} refreshId={refresh} />,
          },
          {
            key: 'public',
            label: (
              <Typography.Text style={{ color: '#0f0' }}>
                <Space>
                  <GlobalOutlined /> Public Libraries
                </Space>
              </Typography.Text>
            ),
            children: <LibraryList type={'public'} refreshId={refresh} />,
          },
          ...(isAdmin
            ? [
                {
                  key: 'all',
                  label: (
                    <Typography.Text>
                      <Space>
                        <FolderOpenOutlined /> All Libraries
                      </Space>
                    </Typography.Text>
                  ),
                  children: <LibraryList type={'all'} refreshId={refresh} />,
                },
              ]
            : []),
        ]}
      />
    </>
  );
};
